    "SCENARIO breaking: NEW_VERSION=2.0.0",
    "SCENARIO mixed: NEW_VERSION=2.4.0",
    "SCENARIO package-json: NEW_VERSION=3.2.2",
    "All integration scenarios passed.",
    "Job succeeded"
)

Write-Host "`nAll tests completed. Results in $ActResultFile"

